import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input by escaping it before outputting it to a web page
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String sanitizedInput = codec.encodeForHTML(userInput);

        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome, " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        // This would output: &lt;script&gt;alert('XSS attack!')&lt;/script&gt; preventing XSS attacks
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
